COPY public.api_module (id, title, description, "order") FROM stdin;
1	Email Basics	Teaches the fundamentals of identifying email phishing attempts, focusing on URLs, sender addresses, and false urgency.	1
2	Mobile & SMS	Teaches you about Mobile and SMS Phishing.	2
3	Voice Phishing (Vishing)	Learn how to identify malicious automated phone calls and voicemails.	3
4	Social Media Phishing	Learn to spot fake profiles, malicious direct messages, and deceptive posts designed to steal your information on popular social platforms.	4
